const msg = $json.message || {};
const text = msg.text || msg.caption || '';
const chatId = msg.chat?.id || $env.TELEGRAM_CHAT_ID;

return [{
  json: {
    source: 'telegram',
    chat_id: chatId,
    raw_text: text.trim(),
    received_at: new Date().toISOString()
  }
}];

