const input = $input.first().json;
let text = input.output?.[0]?.content?.[0]?.text || input.output_text || '{}';

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  parsed = {
    title: $('Eingang normalisieren').first().json.raw_text.slice(0, 120),
    description: 'KI konnte die Eingabe nicht sauber parsen. Original: ' + $('Eingang normalisieren').first().json.raw_text,
    area: 'Sonstiges',
    priority: 3,
    due_date: null,
    reminder_minutes_before: null,
    is_task: true
  };
}

const original = $('Eingang normalisieren').first().json;

if (!parsed.title || parsed.title.trim() === '') {
  parsed.title = original.raw_text.slice(0, 120) || 'Neue Aufgabe';
}

let dueDate = parsed.due_date || null;
// Vikunja erwartet ISO-String oder null.
if (dueDate && !dueDate.includes('T')) {
  dueDate = dueDate + 'T18:00:00+02:00';
}

return [{
  json: {
    chat_id: original.chat_id,
    original_text: original.raw_text,
    title: parsed.title,
    description: [
      parsed.description || '',
      '',
      '---',
      'Quelle: Telegram',
      'Bereich: ' + (parsed.area || 'Sonstiges'),
      'Original: ' + original.raw_text
    ].join('\n'),
    area: parsed.area || 'Sonstiges',
    priority: parsed.priority || 3,
    due_date: dueDate,
    reminder_minutes_before: parsed.reminder_minutes_before || null,
    is_task: parsed.is_task !== false
  }
}];

