const tasks = Array.isArray($json) ? $json : ($json.data || []);
const now = new Date();
const endToday = new Date();
endToday.setHours(23,59,59,999);

const open = tasks.filter(t => !t.done);
const overdue = open.filter(t => t.due_date && new Date(t.due_date) < now);
const today = open.filter(t => t.due_date && new Date(t.due_date) >= now && new Date(t.due_date) <= endToday);
const prio = open.filter(t => !t.due_date).sort((a,b) => (b.priority || 0) - (a.priority || 0)).slice(0,5);

function line(t) {
  const p = t.priority ? 'P' + t.priority : 'P3';
  const due = t.due_date ? new Date(t.due_date).toLocaleString('de-DE', { dateStyle: 'short', timeStyle: 'short' }) : 'ohne Datum';
  return `• ${p} ${t.title} (${due})`;
}

let text = '🌅 *Dein Tagesplan*\n\n';
if (overdue.length) text += `🚨 *Überfällig*\n${overdue.slice(0,10).map(line).join('\n')}\n\n`;
if (today.length) text += `📌 *Heute fällig*\n${today.slice(0,10).map(line).join('\n')}\n\n`;
if (prio.length) text += `🧠 *Wichtig ohne Datum*\n${prio.map(line).join('\n')}\n\n`;
if (!overdue.length && !today.length && !prio.length) text += 'Alles ruhig. Keine offenen Aufgaben für heute gefunden.';

text += '\nRegel: Erledige zuerst 1 kleine Sache. Nicht alles auf einmal.';

return [{ json: { text } }];

const tasks = Array.isArray($json) ? $json : ($json.data || []);
const open = tasks.filter(t => !t.done);
const overdue = open.filter(t => t.due_date && new Date(t.due_date) < new Date());

let text = '🌙 *Abendcheck*\n\n';
text += `Offene Aufgaben gesamt: *${open.length}*\n`;
text += `Überfällig: *${overdue.length}*\n\n`;

if (overdue.length) {
  text += '🚨 Bitte morgen zuerst diese Dinge anfassen:\n';
  text += overdue.slice(0,8).map(t => `• ${t.title}`).join('\n');
} else {
  text += 'Keine überfälligen Aufgaben. Stark.';
}

text += '\n\nSchreib mir einfach neue Dinge per Telegram, z. B.:\n„Morgen 10 Uhr TÜV Termin machen“';

return [{ json: { text } }];

const tasks = Array.isArray($json) ? $json : ($json.data || []);
const now = new Date();
const week = new Date();
week.setDate(week.getDate() + 7);

const open = tasks.filter(t => !t.done);
const next7 = open.filter(t => t.due_date && new Date(t.due_date) <= week).sort((a,b) => new Date(a.due_date) - new Date(b.due_date));
const noDate = open.filter(t => !t.due_date).sort((a,b) => (b.priority || 0) - (a.priority || 0)).slice(0,10);

function line(t) {
  const due = t.due_date ? new Date(t.due_date).toLocaleDateString('de-DE') : 'ohne Datum';
  return `• P${t.priority || 3} ${t.title} (${due})`;
}

let text = '🗓️ *Wochenplanung*\n\n';
text += `Nächste 7 Tage: *${next7.length}* Aufgaben\n`;
text += `Ohne Datum: *${open.filter(t => !t.due_date).length}* Aufgaben\n\n`;

if (next7.length) text += `📌 *Diese Woche*\n${next7.slice(0,15).map(line).join('\n')}\n\n`;
if (noDate.length) text += `📥 *Bitte einplanen / löschen / delegieren*\n${noDate.map(line).join('\n')}\n\n`;

text += 'Regel für Sonntag: Alles ohne Datum entweder terminieren oder löschen.';

return [{ json: { text } }];
